// ── Helper functions ──

/** Get all schools in a specific conference */
export function getSchoolsByConference(conference: string): D3School[] {
  return d3Schools.filter(s => s.conference === conference);
}

/** Get all schools in a specific state */
export function getSchoolsByState(state: string): D3School[] {
  return d3Schools.filter(s => s.state === state);
}

/** Search schools by name (case-insensitive partial match) */
export function searchSchools(query: string): D3School[] {
  const q = query.toLowerCase();
  return d3Schools.filter(s => 
    s.name.toLowerCase().includes(q) || 
    s.mascot.toLowerCase().includes(q) ||
    s.conference.toLowerCase().includes(q)
  );
}

/** Get all unique conference names */
export function getAllConferences(): string[] {
  return Array.from(new Set(d3Schools.map(s => s.conference))).sort();
}

/** Get schools near Wisconsin (WIAC, CCIW, MWC, NACC, MIAC conferences) */
export function getWisconsinAreaSchools(): D3School[] {
  const wiAreaConfs = ['WIAC', 'CCIW', 'MWC', 'NACC', 'MIAC'];
  return d3Schools.filter(s => wiAreaConfs.includes(s.conference) || s.state === 'WI');
}
